90	    v.PhaseOffs_0 := phi_offset_i;
91	
92	    -- Phase accu (count after sample to start at zero)
93	    if vld_i = '1' then
94	      -- Phase zero must be output for the first sample after reset, this is achieved by r.FirstSplCnt_0
95	      if restart_i = '1' or r.FirstSplCnt_0 /= 0 then
