1	------------------------------------------------------------------------------
2	--  Copyright (c) 2018 by Paul Scherrer Institute, Switzerland
3	--  All rights reserved.
4	--  Authors: Oliver Bruendler, Benoit Stef, Radoslaw Rybaniec
5	------------------------------------------------------------------------------
6	
7	------------------------------------------------------------------------------
8	-- Description
9	------------------------------------------------------------------------------
10	-- This entity is a simple demodulator with real input and complex output. It
11	-- demodulates the signal and filters the results with a comb-filter of length
12	-- 1/Fcarrier (zeros at Fcarrier where DC ends up and Fcarrier*2 where the
13	-- demodulation alias occurs).
14	-- The demodulator only works well for very narrowband signals with very little
15	-- out of band noise. The signal frequency must be an integer multiple of the
16	-- sample frequency.
17	------------------------------------------------------------------------------
18	
19	library ieee;
20	use ieee.std_logic_1164.all;
21	use ieee.numeric_std.all;
22	use ieee.math_real.all;
23	
24	use work.psi_common_math_pkg.all;
25	use work.psi_fix_pkg.all;
26	
27	-- $$ processes=stim,check $$
28	-- @formatter:off
29	entity psi_fix_demod_real2cplx is
30	  generic(
31	    rst_pol_g     : std_logic := '1';                                                  -- reset polarity active high ='1'    $$ constant = '1' $$
32	    in_fmt_g      : psi_fix_fmt_t;                                                     -- input format FP                    $$ constant=(1,0,15) $$
33	    out_fmt_g     : psi_fix_fmt_t;                                                     -- output format FP                   $$ constant=(1,0,16) $$
34	    coef_bits_g   : positive  := 18;                                                   -- internal coefficent number of bits $$ constant=25 $$
35	    channels_g    : natural   := 1;                                                    -- number of channels TDM             $$ constant=2 $$
36	    ratio_num_g   : natural   := 5;                                                    -- ratio numerator between clock and IF/RF      $$ constant=5 $$
37	    ratio_den_g : natural   := 1                                                       -- ratio denominator between clock and IF/RF    $$ constant=1 $$
38	  );
39	  port(
40	    clk_i        : in  std_logic;                                                       -- clk system $$ type=clk; freq=100e6 $$
41	    rst_i        : in  std_logic;                                                       -- rst system $$ type=rst; clk=clk_i $$
42	    dat_i        : in  std_logic_vector(psi_fix_size(in_fmt_g)*channels_g - 1 downto 0);-- data input IF/RF
43	    vld_i        : in  std_logic;                                                       -- valid input freqeuncy sampling
44	    phi_offset_i : in  std_logic_vector(log2ceil(ratio_num_g)-1 downto 0);              -- phase offset for demod LUT
45	    dat_inp_o    : out std_logic_vector(psi_fix_size(out_fmt_g)*channels_g- 1 downto 0);-- inphase data output
46	    dat_qua_o    : out std_logic_vector(psi_fix_size(out_fmt_g)*channels_g- 1 downto 0);-- quadrature data output
47	    vld_o        : out std_logic                                                        -- valid output
48	  );
49	end entity;
50	-- @formatter:on
51	architecture RTL of psi_fix_demod_real2cplx is
52	
53	  constant coefUnusedBits_c : integer     := log2(ratio_num_g);
54	  constant CoefFmt_c        : psi_fix_fmt_t := (1, 0-coefUnusedBits_c, coef_bits_g + coefUnusedBits_c-1);
55	  constant MultFmt_c        : psi_fix_fmt_t := (1, in_fmt_g.I + CoefFmt_c.I, out_fmt_g.F+log2ceil(ratio_num_g)+2); -- truncation error does only lead to 1/4 LSB error on output
56	  constant coef_scale_c     : real        := (1.0-2.0**(-real(CoefFmt_c.F)))/real(ratio_num_g); -- prevent +/- 1.0 and pre-compensate for gain of moving average
57	
58	  type coef_array_t is array (0 to ratio_num_g - 1) of std_logic_vector(psi_fix_size(CoefFmt_c) - 1 downto 0);
59	
60	  --SIN coef function <=> Q coef n = (sin(nx2pi/Ratio)(2/Ratio))
61	  function coef_sin_array_func return coef_array_t is
62	    variable array_v : coef_array_t;
63	  begin
64	    for i in 0 to ratio_num_g - 1 loop
65	      array_v(i) := psi_fix_from_real(sin(2.0 * MATH_PI * real(i) / real(ratio_num_g)) * coef_scale_c, CoefFmt_c);
66	    end loop;
67	    return array_v;
68	  end function;
69	
70	  --COS coef function <=> Q coef n = (cos(nx2pi/Ratio)(2/Ratio))
71	  function coef_cos_array_func return coef_array_t is
72	    variable array_v : coef_array_t;
73	  begin
74	    for i in 0 to ratio_num_g - 1 loop
75	      array_v(i) := psi_fix_from_real(cos(2.0 * MATH_PI * real(i) / real(ratio_num_g)) * coef_scale_c, CoefFmt_c);
76	    end loop;
77	    return array_v;
78	  end function;
79	
80	  -- I coef n = (sin(nx2pi/5)(2/5))
81	  constant nonIQ_table_sin : coef_array_t := coef_sin_array_func;
82	  -- Q coef n = (cos(nx2pi/5)(2/5))
83	  constant nonIQ_table_cos : coef_array_t := coef_cos_array_func;
84	  --xilinx constraint
85	  attribute rom_style      : string;
86	  attribute rom_style of nonIQ_table_sin, nonIQ_table_cos : constant is "distributed";
87	
88	  type MultArray_t is array (0 to channels_g - 1) of std_logic_vector(psi_fix_size(MultFmt_c) - 1 downto 0);
89	  type InArray_t is array (0 to channels_g - 1) of std_logic_vector(psi_fix_size(in_fmt_g) - 1 downto 0);
90	  type OutArray_t is array (0 to channels_g - 1) of std_logic_vector(psi_fix_size(out_fmt_g) - 1 downto 0);
91	  --
92	  signal cptInt        : integer range 0 to ratio_den_g*ratio_num_g - 1 := 0;
93	  signal cpt_s         : integer range 0 to ratio_num_g - 1 := 0;
94	  signal mult_i_s      : MultArray_t;
95	  signal mult_q_s      : MultArray_t;
96	  --
97	  signal mult_i_dff_s  : MultArray_t;
98	  signal mult_q_dff_s  : MultArray_t;
99	  signal mult_i_dff2_s : MultArray_t;
100	  signal mult_q_dff2_s : MultArray_t;
101	  signal coef_i_s      : std_logic_vector(psi_fix_size(CoefFmt_c) - 1 downto 0);
102	  signal coef_q_s      : std_logic_vector(psi_fix_size(CoefFmt_c) - 1 downto 0);
103	  signal data_s        : InArray_t;
104	  signal data_dff_s    : InArray_t;
105	  signal out_q_s       : OutArray_t;
106	  signal out_i_s       : OutArray_t;
