32	          int_fmt_g     : psi_fix_fmt_t        := (1, 1, 15);             -- internal format computation $$ constant=(1,1,15) $$
33	          out_fmt_g     : psi_fix_fmt_t        := (1, 1, 15);             -- output format FP $$ constant=(1,1,15) $$
34	          ratio_num_g   : natural              := 5;                      -- ratio for deciamtion (numerator) $$ constant=5 $$
35	          ratio_den_g   : natural              := 1                       -- ratio for decimation (denominator) $$ constant=1 $$  
36	         );
37	  port(
38	    clk_i     : in  std_logic;                                            -- $$ type=clk; freq=100e6 $$
39	    rst_i     : in  std_logic;                                            -- $$ type=rst; clk=clk_i $$
40	    dat_inp_i : in  std_logic_vector(psi_fix_size(inp_fmt_g)-1 downto 0); -- in-phase    data
41	    dat_qua_i : in  std_logic_vector(psi_fix_size(inp_fmt_g)-1 downto 0); -- quadrature data
42	    vld_i     : in  std_logic;                                            -- valid input frequency sampling
43	    dat_o     : out std_logic_vector(psi_fix_size(out_fmt_g)-1 downto 0); -- data output IF/RF
44	    vld_o     : out std_logic                                             -- valid output frequency sampling
45	  );
46	end entity;
47	--@formatter:on
48	architecture rtl of psi_fix_mod_cplx2real is
49	
50	  type coef_array_t is array (0 to ratio_num_g - 1) of std_logic_vector(psi_fix_size(coef_fmt_g) - 1 downto 0);
51	  constant coef_scale_c : real := 1.0 - 1.0 / 2.0**(real(coef_fmt_g.F)); -- prevent +/- 1.0 -
52	  ------------------------------------------------------------------------------
53	  --Sin coef function <=> Q coef n = (cos(nx2pi/Ratio))
54	  ------------------------------------------------------------------------------
55	
56	  function coef_sin_array_func return coef_array_t is
57	    variable array_v : coef_array_t;
58	  begin
59	    for i in 0 to ratio_num_g - 1 loop
