105	  signal datInp_s  : std_logic_vector(psi_fix_size(inp_fmt_g) - 1 downto 0);
106	  signal datInp1_s : std_logic_vector(psi_fix_size(inp_fmt_g) - 1 downto 0);
107	  signal datQua_s  : std_logic_vector(psi_fix_size(inp_fmt_g) - 1 downto 0);
108	  signal datQua1_s : std_logic_vector(psi_fix_size(inp_fmt_g) - 1 downto 0);
109	  --signal debug0_s  : unsigned(log2ceil(ratio_num_g*ratio_den_g)-1 downto 0);
110	
111	begin
