126	      if rst_i = rst_pol_g then
127	        cpt_v := 0;
128	      else
129	        if vld_i = '1' then
130	          if cpt_v < ratio_num_g - ratio_den_g then
131	            cpt_v := cpt_v + ratio_den_g;
132	          else
133	            cpt_v := ratio_den_g - (ratio_num_g - cpt_v);
134	          end if;
